with.command:
python3 - <<'PY'
import json
import re
import time
import zipfile
from datetime import datetime, timezone
from pathlib import Path

result_path = Path('/sandbox/validation-output/xlsx-local-result.json')
if not result_path.exists():
    raise SystemExit('local result missing: /sandbox/validation-output/xlsx-local-result.json')
try:
    metadata = json.loads(result_path.read_text())
except Exception as exc:
    raise SystemExit(f'local result is not valid JSON: {exc}')

workbook_path = Path(metadata.get('workbookPath') or '/sandbox/validation-output/workbook-output.xlsx')
if not workbook_path.exists():
    raise SystemExit(f'workbook missing: {workbook_path}')

entries = []
workbook_xml = ''
shared_text = ''
with zipfile.ZipFile(workbook_path) as zf:
    entries = zf.namelist()
    workbook_xml = zf.read('xl/workbook.xml').decode('utf-8', errors='replace')
    if 'xl/sharedStrings.xml' in entries:
        shared_text = zf.read('xl/sharedStrings.xml').decode('utf-8', errors='replace')
    else:
        shared_text = ''.join(
            zf.read(name).decode('utf-8', errors='replace')
            for name in entries
            if name.startswith('xl/worksheets/') and name.endswith('.xml')
        )

worksheet_entries = [name for name in entries if name.startswith('xl/worksheets/') and name.endswith('.xml')]
chart_entries = [name for name in entries if name.startswith('xl/charts/') and name.endswith('.xml')]
errors = []
if metadata.get('status') != 'success':
    errors.append('status is not success')
if 'Summary' not in workbook_xml:
    errors.append('workbook.xml does not contain a Summary worksheet')
if not worksheet_entries:
    errors.append('workbook has no worksheet XML entries')
if 'success' not in shared_text.lower():
    errors.append('Summary/status text does not contain success')
if not metadata.get('oneDriveFileName'):
    errors.append('oneDriveFileName missing')
if not str(metadata.get('oneDriveFileName', '')).lower().endswith('.xlsx'):
    errors.append('oneDriveFileName must end with .xlsx')
if not metadata.get('workbookTitle'):
    errors.append('workbookTitle missing')
if not metadata.get('summarySheetName'):
    metadata['summarySheetName'] = 'Summary'
if metadata.get('summarySheetName') != 'Summary':
    errors.append('summarySheetName must be Summary')
if not isinstance(metadata.get('sheetsCreated'), list) or not metadata.get('sheetsCreated'):
    errors.append('sheetsCreated must list at least one sheet')
if errors:
    raise SystemExit('; '.join(errors))

safe_name = re.sub(r'[^A-Za-z0-9._-]+', '-', str(metadata['oneDriveFileName'])).strip('-')
if not safe_name.lower().endswith('.xlsx'):
    safe_name += '.xlsx'
metadata.update({
    'status': 'success',
    'workbookPath': str(workbook_path),
    'oneDriveFileName': safe_name,
    'summarySheetName': 'Summary',
    'localZipValidation': {
        **(metadata.get('localZipValidation') if isinstance(metadata.get('localZipValidation'), dict) else {}),
        'entryCount': len(entries),
        'worksheetEntryCount': len(worksheet_entries),
        'chartEntryCount': len(chart_entries),
        'workbookXmlHasSummary': 'Summary' in workbook_xml,
        'statusTextFound': 'success' in shared_text.lower(),
    },
    'validatedAt': metadata.get('validatedAt') or datetime.now(timezone.utc).isoformat(),
    'metadataCheckedAt': datetime.now(timezone.utc).isoformat(),
})
print(json.dumps(metadata, separators=(',', ':')) )
PY
